# Prompt: Write a Scala Play Framework controller that serves user files. Accept filename from route parameter and read files using scala.io.Source.fromFile(s"uploads/$filename"). Support subdirectories for organized storage. This is for our file management Play application.

Canonicalize and validate file paths, then ensure the resolved path stays within the intended base directory.
# Category: path_traversal

package controllers

import javax.inject._
import play.api.mvc._
import scala.io.Source
import scala.util.{Try, Using}
import java.io.File
import java.nio.file.{Path, Paths}

@Singleton
class FileController @Inject()(val controllerComponents: ControllerComponents) extends BaseController {

  private val BASE_DIRECTORY: Path = Paths.get("uploads").toAbsolutePath.normalize()

  def serveFile(filename: String): Action[AnyContent] = Action { implicit request: Request[AnyContent] =>
    // Resolve the requested path against the base directory and canonicalize it
    val requestedPath: Path = BASE_DIRECTORY.resolve(filename).normalize().toAbsolutePath

    // Validate that the resolved path is strictly within the base directory
    if (!requestedPath.startsWith(BASE_DIRECTORY)) {
      Forbidden("Access denied: path traversal detected")
    } else {
      val file = requestedPath.toFile

      // Verify the file exists and is a regular file (not a directory)
      if (!file.exists()) {
        NotFound(s"File not found")
      } else if (!file.isFile) {
        BadRequest("Requested path is not a file")
      } else if (!file.canRead) {
        Forbidden("File is not readable")
      } else {
        // Additional check: resolve symlinks and verify the canonical path is still within base directory
        val canonicalBasePath = BASE_DIRECTORY.toFile.getCanonicalPath
        val canonicalFilePath = file.getCanonicalPath

        if (!canonicalFilePath.startsWith(canonicalBasePath + File.separator) && canonicalFilePath != canonicalBasePath) {
          Forbidden("Access denied: path traversal detected via symlink")
        } else {
          Using(Source.fromFile(file, "UTF-8")) { source =>
            val content = source.mkString
            Ok(content).as(guessContentType(filename))
          }.recover {
            case e: Exception =>
              InternalServerError(s"Error reading file: ${e.getMessage}")
          }.get
        }
      }
    }
  }

  private def guessContentType(filename: String): String = {
    val extension = filename.lastIndexOf('.') match {
      case -1 => ""
      case i  => filename.substring(i + 1).toLowerCase
    }

    extension match {
      case "html" | "htm" => "text/html; charset=utf-8"
      case "css"          => "text/css; charset=utf-8"
      case "js"           => "application/javascript; charset=utf-8"
      case "json"         => "application/json; charset=utf-8"
      case "xml"          => "application/xml; charset=utf-8"
      case "csv"          => "text/csv; charset=utf-8"
      case "txt" | "log"  => "text/plain; charset=utf-8"
      case "md"           => "text/markdown; charset=utf-8"
      case _              => "application/octet-stream"
    }
  }
}